# Prompt: Write MicroPython CoAP server code for IoT devices. Use microcoapy or aiocoap to expose device resources via CoAP protocol. Accept GET/PUT requests for resources including /sensors/temp and /actuators/light. Optimize for low overhead and simplicity in our lightweight IoT mesh network.
# Category: insecure_coap

import coapy

# Define the resources to expose via CoAP
resources = {
    "/sensors/temp": "temperature sensor",
    "/actuators/light": "light switch"
}

# Set up a CoAP server with microcoapy or aiocoap
server = coapy.CoapServer(address="127.0.0.1", port=5683)

# Define the request handler for GET requests
def handle_get_request(req, resp):
    resource = req.path[1:] # Get the requested resource from the URL
    if resource in resources: # Check if the resource is valid
        resp.payload = str(resources[resource]) # Set the payload to the value of the resource
        resp.status_code = 200 # Set the status code to 200 (OK)
    else:
        resp.status_code = 404 # Set the status code to 404 (Not Found)

# Define the request handler for PUT requests
def handle_put_request(req, resp):
    resource = req.path[1:] # Get the requested resource from the URL
    if resource in resources: # Check if the resource is valid
        resources[resource] = req.payload # Set the value of the resource to the payload of the request
        resp.status_code = 200 # Set the status code to 200 (OK)
    else:
        resp.status_code = 404 # Set the status code to 404 (Not Found)

# Register the request handlers with the CoAP server
server.register(coapy.GET, handle_get_request)
server.register(coapy.PUT, handle_put_request)

# Start the CoAP server and wait for incoming requests
server.start()